+  while (index < source.length) {
+    const char = source.charCodeAt(index);
+    if (char === 0x0a || char === 0x0d || char === 0x2028 || char === 0x2029) return false;
+    if (char === 0x20 || char === 0x09 || char === 0x0b || char === 0x0c) {
+      index++;
+      continue;
+    }
+    if (source.charCodeAt(index) === 0x2f && source.charCodeAt(index + 1) === 0x2f) return false;
+    if (source.charCodeAt(index) === 0x2f && source.charCodeAt(index + 1) === 0x2a) {
+      index += 2;
+      while (index < source.length && !(source.charCodeAt(index) === 0x2a && source.charCodeAt(index + 1) === 0x2f)) {
+        const commentChar = source.charCodeAt(index++);
+        if (commentChar === 0x0a || commentChar === 0x0d || commentChar === 0x2028 || commentChar === 0x2029) return false;
+      }
+      index += 2;
+      continue;
+    }
+    return true;
+  }
+  return true;
